INSERT INTO heritage_sites (site_id, site_code, name, type, category, level, province_code, city_code, address, latitude, longitude, location_point, cover_image, description, history, status, is_recommended, create_time, update_time) VALUES
('bj1', 'BJ001', '故宫博物院', 1, '博物馆', '国家级', '110000', '110100', '北京市东城区景山前街4号', 39.9163, 116.3972, ST_GeomFromText('POINT(39.9163 116.3972)', 4326), '/images/gugong-taihedian.jpg', '中国最大的古代文化艺术博物馆，世界五大宫殿之首', '故宫又称紫禁城，是明清两代的皇家宫殿，是世界上现存规模最大、保存最为完整的木质结构古建筑群。', 1, 1, NOW(), NOW()),
('bj2', 'BJ002', '中国国家博物馆', 1, '博物馆', '国家级', '110000', '110100', '北京市东城区东长安街16号', 39.9054, 116.3976, ST_GeomFromText('POINT(39.9054 116.3976)', 4326), '/images/bj2中国国家博物馆.jpg', '世界上单体建筑面积最大的博物馆，藏品143万余件', '中国国家博物馆是世界上单体建筑面积最大的博物馆，馆藏文物143万余件。', 1, 1, NOW(), NOW()),
('bj3', 'BJ003', '天坛', 2, '古建筑', '国家级', '110000', '110100', '北京市东城区天坛内东里7号', 39.8822, 116.4066, ST_GeomFromText('POINT(39.8822 116.4066)', 4326), '/images/tiantan-qiniandian.jpg', '明清两代皇帝祭天的场所，世界文化遗产', '天坛始建于明永乐年间，是明清两代皇帝祭天、祈谷的场所。', 1, 1, NOW(), NOW()),
('bj4', 'BJ004', '颐和园', 4, '皇家园林', '国家级', '110000', '110108', '北京市海淀区新建宫门路19号', 39.9999, 116.2755, ST_GeomFromText('POINT(39.9999 116.2755)', 4326), '/images/yiheyuan-changlang.jpg', '中国现存规模最大的皇家园林，世界文化遗产', '颐和园是中国现存规模最大、保存最完整的皇家园林。', 1, 1, NOW(), NOW()),
('bj5', 'BJ005', '首都博物馆', 1, '博物馆', '国家级', '110000', '110102', '北京市西城区复兴门外大街16号', 39.9073, 116.3516, ST_GeomFromText('POINT(39.9073 116.3516)', 4326), '/images/bj5首都博物馆.jpg', '展示北京历史文化的综合性博物馆', '首都博物馆是一座展示北京历史文化的综合性博物馆。', 1, 1, NOW(), NOW()),
('bj6', 'BJ006', '雍和宫', 2, '古建筑', '国家级', '110000', '110101', '北京市东城区雍和宫大街12号', 39.9474, 116.4175, ST_GeomFromText('POINT(39.9474 116.4175)', 4326), '/images/bj6雍和宫.jpg', '北京最大的藏传佛教寺院，曾是雍正皇帝府邸', '雍和宫原为雍正皇帝府邸，后改为藏传佛教寺院，是北京最大的藏传佛教寺院。', 1, 1, NOW(), NOW()),
('qy1', 'QY001', '清远市博物馆', 1, '博物馆', '市级', '440000', '441800', '清远市清城区银泉北路', 23.7066, 113.0541, ST_GeomFromText('POINT(23.7066 113.0541)', 4326), '/images/qy1清远市博物馆.jpg', '展示清远历史文化，收藏大量珍贵文物', '清远市博物馆是一座综合性博物馆，收藏有大量反映清远历史文化的珍贵文物，是了解清远历史的重要窗口。', 1, 1, NOW(), NOW()),
('qy2', 'QY002', '飞来寺', 2, '古建筑', '省级', '440000', '441800', '清远市清城区飞来峡', 23.6892, 113.1234, ST_GeomFromText('POINT(23.6892 113.1234)', 4326), '/images/qy2飞来寺.jpg', '始建于梁武帝时期，千年古刹，岭南名寺', '飞来寺始建于南朝梁武帝时期，距今已有1500多年历史，是岭南地区著名的佛教圣地。', 1, 1, NOW(), NOW()),
('qy3', 'QY003', '连州地下河', 3, '自然景观', '国家级', '440000', '441882', '清远市连州市东陂镇', 24.7806, 112.3814, ST_GeomFromText('POINT(24.7806 112.3814)', 4326), '/images/qy3连州地下河.jpg', '典型的亚热带喀斯特地貌溶洞，被誉为广东地下第一河', '连州地下河是一处典型的亚热带喀斯特地貌溶洞，洞内河流蜿蜒，钟乳石千姿百态。', 1, 1, NOW(), NOW()),
('qy4', 'QY004', '英德宝晶宫', 3, '自然景观', '省级', '440000', '441881', '清远市英德市燕子岩', 24.1856, 113.4012, ST_GeomFromText('POINT(24.1856 113.4012)', 4326), '/images/qy4英德宝晶宫.jpg', '集溶洞、湖泊、山林于一体的综合性景区', '宝晶宫是一处集溶洞、湖泊、山林于一体的综合性景区，洞内石笋、石柱、石幔千姿百态。', 1, 1, NOW(), NOW()),
('qy5', 'QY005', '瑶族文化博物馆', 1, '博物馆', '省级', '440000', '441826', '清远市连南瑶族自治县', 24.1706, 112.0876, ST_GeomFromText('POINT(24.1706 112.0876)', 4326), '/images/qy5瑶族文化博物馆.jpg', '展示瑶族历史文化，体验瑶族风情', '瑶族文化博物馆位于连南瑶族自治县，是全国首家瑶族专题博物馆。', 1, 1, NOW(), NOW());
